import { Event } from 'jibo-typed-events';
import { Log as JiboLog } from 'jibo-log';
import {HotwordListenMode as Mode, SuccessTurnResult, HJMode, ListenTurnResult, TurnResultType} from './Types';
import * as api from './Api';
import {SubscribeGlobalRequest} from './Request';

//track active tokens so that we may keep track of what modes and rules are active
const ACTIVE_TOKENS:HotwordModeToken[][] = [
    [],//Mode.Disabled
    [],//Mode.HJ_Only
    [],//Mode.ASR_Only
    [],//Mode.Custom_NLU_Only
    []//Mode.Custom_NLU_Added
];

//just keeping track of what mode we are currently in for faster updating
let previousMode:Mode = Mode.Normal;
//subscribe global request to disable rules for ASR_Only mode
let asrOnlyRequest:SubscribeGlobalRequest = null;

//internal utility function, to see if a list of rules shares any entries with another list
function rulesIntersect(arr1:string[], arr2:string[]):boolean {
    if (!arr1 || !arr2) {
        return false;
    }
    return arr1.some((n) => arr2.includes(n));
}

//initialized when client is initialized
let log: JiboLog;
/**
 * @private
 */
export function init(parentLog: JiboLog) {
    log = parentLog.createChild('HotwordMode');
    api.events.connect.on(onReconnect);
}

/**
 * Token representing a call to jibo.jetstream.setHotwordMode().
 * @class jibo.jetstream.HotwordModeToken
 */
export class HotwordModeToken {
    /**
     * @private
     */
    public mode: Mode;

    /**
     * @private
     */
    public rules: string[];

    /**
     * Promise for when the mode is fully active, if you wanted to wait on it.
     * @name jibo.jetstream.HotwordModeToken#activated
     * @type {Promise<void>}
     */
    public activated: Promise<void>;

    /**
     * `Global match`
     * @name jibo.jetstream.HotwordModeToken#match
     * @type {Event<jibo.jetstream.types.SuccessTurnResult>}
     */
    public match:Event<SuccessTurnResult>;

    /**
     * @name jibo.jetstream.HotwordModeToken#globalRequest
     * @type {jibo.jetstream.request.SubscribeGlobalRequest}
     * @private
     */
    public globalRequest:SubscribeGlobalRequest;
    /**
     * If token has not been released.
     * @name jibo.jetstream.HotwordModeToken#valid
     * @type {boolean}
     * @private
     */
    private valid:boolean = true;

    /**
     * @hideConstructor
     */
    constructor(mode: Mode, rules?:string[]) {
        this.mode = mode;
        this.rules = rules || [];
        this.match = new Event<SuccessTurnResult>(`Global match`);
        this.onGlobalResult = this.onGlobalResult.bind(this);
    }

    /**
     * Releases the token, permanently disabling it.
     * @method jibo.jetstream.HotwordModeToken#release
     * @returns {Promise<void>}
     */
    public async release(): Promise<void> {
        await this.cleanup();
        // remove the token from the hotword control system
        try {
            await removeToken(this);
        } catch (e) {
            //if next mode could not be set, then that doesn't mean that the remove token failed
            log.warn('Next mode could not be set when removing a token', e);
        }
    }
    
    /**
     * Cleanup without modifying hotword mode. This way we can remove tokens en-masse
     * and update the mode once at the end.
     * @private
     */
    public async cleanup(): Promise<void> {
        //remove any match listeners
        this.match.removeAllListeners();
        //token is no longer valid
        this.valid = false;
        //wait until the token became active before removing it, to cover lag time in updating
        //HJ enabled status or any other token prep time
        try {
            await this.activated;
        } catch (e) {
            //if the token failed to activate, should still try to remove it from the system
            log.warn('Releasing a token but it failed to activate', e);
        }
        //immediately unsubscribe global request if present (method can't reject)
        await this.removeSubscribeGlobalRequest();
    }

    /**
     * @private
     */
    public acceptSubscribeGlobalRequest(request:SubscribeGlobalRequest) {
        //if we have been released, should bail (and also unsubscribe
        //the request)
        if (!this.valid) {
            request.unsubscribe();
            return;
        }
        this.globalRequest = request;
        //send match events through
        api.events.globalTurnResult.on(this.onGlobalResult);
    }

    /**
     * @private
     */
    public async removeSubscribeGlobalRequest() {
        api.events.globalTurnResult.off(this.onGlobalResult);
        if (this.globalRequest) {
            try {
                //unsubscribe the request (getting local var so we can null out the property now)
                const request = this.globalRequest;
                this.globalRequest = null;
                await request.unsubscribe();
            } catch (e) {
                //failed to unsubscribe, oh well - probably was already unsubscribed but we don't
                //want to rock the boat by throwing an error
                log.info('Failed to unsubscribe a global request from a token', e);
            }
        }
    }

    private onGlobalResult(result:ListenTurnResult) {
        if (result.status === TurnResultType.SUCCEEDED && result.result.nlu && rulesIntersect(result.result.nlu.rules, this.rules)) {
            this.match.emit(result);
        }
    }
}

export function generateToken(mode: Mode, rules?:string[]) {
    const token = new HotwordModeToken(mode, rules);
    if (mode === Mode.Normal) {
        //good work, you generated a handle for the default mode that won't do anything
        token.activated = Promise.resolve();
        return token;
    }
    //if mode is not a value of HotwordModeToken (numeric enums reflect back to their names), then
    //bail early, but reject the activated promise
    if (typeof Mode[mode] !== 'string') {
        token.activated = Promise.reject(`Invalid mode: ${mode}`);
        return token;
    }
    ACTIVE_TOKENS[mode].push(token);
    token.activated = updateMode(mode);
    return token;
}

//drops all tokens and returns the mode to Normal
export async function resetMode(): Promise<void> {
    //clear out all tokens
    const tokenCleanup: Promise<void>[] = [];
    for (let i = Mode.Disabled; i < Mode.Normal; ++i) {
        //clean up and invalidate tokens
        tokenCleanup.push(...ACTIVE_TOKENS[i].map(token => token.cleanup()));
        ACTIVE_TOKENS[i].length = 0;
    }
    await Promise.all(tokenCleanup);
    //update the mode to normal mode
    return updateMode(Mode.Normal);
}

//removes a token and upates the mode
async function removeToken(token:HotwordModeToken):Promise<void> {
    //just in case someone is silly
    if (token.mode === Mode.Normal) {
        return Promise.resolve();
    }
    //remove token from list
    const list = ACTIVE_TOKENS[token.mode];
    //ensure list exists for safety
    if (!list) {
        return Promise.reject(`Invalid mode: ${token.mode}`);
    }
    //ensure token is in the list - already released tokens shouldn't have any ill effects if
    //released again
    const index = list.indexOf(token);
    if (index === -1) {
        return Promise.resolve();
    }
    //remove token
    list.splice(index, 1);
    //if token wasn't the active mode, then no need to update the mode
    if (token.mode > previousMode) {
        return Promise.resolve();
    }
    //determine what mode we should be in now
    for (let i = Mode.Disabled; i < Mode.Normal; ++i) {
        if (ACTIVE_TOKENS[i].length) {
            return updateMode(i);
        }
    }
    //back to normal mode
    return updateMode(Mode.Normal);
}

//internally updates the current mode so that it is accurate
async function updateMode(newMode:Mode) {
    //locally cache the previous mode so that we can update previousMode immediately
    //and may return anywhere we want
    const tempPrevMode = previousMode;
    previousMode = newMode;
    //if we are in ASR only mode, we need to unsubscribe any Custom_NLU_Only level rules so that
    //they aren't also applied (because they are all exclusive globals)
    if (newMode === Mode.ASR_Only) {
        await Promise.all(ACTIVE_TOKENS[Mode.Custom_NLU_Only].map(token => token.removeSubscribeGlobalRequest().catch((e)=>{
            log.info('Failed to unsubscribe global rules with token ', e);
        })));
    }
    //clear our global rule disabling request if we are leaving ASR_Only mode
    if (tempPrevMode !== newMode && tempPrevMode === Mode.ASR_Only) {
        try {
            await asrOnlyRequest.unsubscribe();
            asrOnlyRequest = null;
        } catch (e) {
            log.warn('Unable to unsubscribe asrOnlyRequest token', e);
            asrOnlyRequest = null;
        }
    }
    //HJ disabled handling is easy
    if (newMode === Mode.Disabled) {
        if (tempPrevMode !== newMode) {
            return api.setHJMode(HJMode.IGNORE_HJ);
        }
        //if already disabled, just bail
        return;
    }
    switch (newMode) {
        case Mode.HJ_Only:
            //tell jetstream to disable turns in response to HJ
            await api.setHJMode(HJMode.ONLY_HJ);
            break;
        case Mode.ASR_Only:
            //additional rules were wiped already, just need to do an exclusive subscribe global
            //to disable launch rules/global commands
            if (!asrOnlyRequest) {
                asrOnlyRequest = await api.subscribeGlobal({
                    nluRules: [],
                    exclusive: true
                });
            }
            break;
        case Mode.Custom_NLU_Only:
        case Mode.Custom_NLU_Added:
            //new rules will be subscribed later in the function
        case Mode.Normal:
            //nothing to do here
            break;
        default:
            //also nothing to do here, treat any bad values like Mode.Normal
    }
    //in any mode other than ASR_Only, we want to allow global rules to be applied to non HJ listens
    //so we need to make sure that the rules are subscribed
    if (newMode !== Mode.ASR_Only) {
        //subscribe all global rules for the active mode
        await buildRuleList();
    }
    if (tempPrevMode === Mode.Disabled || tempPrevMode === Mode.HJ_Only) {
        //if the previous HJ mode was disabled, then we should re-enable HJ now, after all globals have been set up
        return api.setHJMode(HJMode.NORMAL_HJ);
    }
}

async function buildRuleList() {
    //get all unsubscribed tokens and subscribe them
    const newTokens:HotwordModeToken[] = [
        //any non-exclusive rules
        ...ACTIVE_TOKENS[Mode.Custom_NLU_Added].filter(token => !token.globalRequest),
        //any exclusive rules
        ...ACTIVE_TOKENS[Mode.Custom_NLU_Only].filter(token => !token.globalRequest)
    ];
    return subscribeRules(newTokens);
}

function subscribeRules(tokens:HotwordModeToken[]) {
    return Promise.all(tokens.map((token) => {
        return api.subscribeGlobal({
            nluRules: token.rules,
            exclusive: token.mode === Mode.Custom_NLU_Only
        }).then((request) => {
            token.acceptSubscribeGlobalRequest(request);
        });
    }));
}

async function onReconnect() {
    //remove SubscribeGlobalRequests for all tokens
    const tokens = [...ACTIVE_TOKENS[Mode.Custom_NLU_Added], ...ACTIVE_TOKENS[Mode.Custom_NLU_Only]];
    tokens.forEach((token) => {
        token.globalRequest = null;
    });
    //reset the mode back to Normal
    const prevMode = previousMode;
    previousMode = Mode.Normal;
    //now restore the state that we were in, resubscribing all rules/requests as appropriate
    updateMode(prevMode);
}
