import { ExtPromiseWrapper } from 'jibo-cai-utils';
import * as types from './Types';

interface RegistryEntry {
    timestamp: number;
    transID: string;
    response: ExtPromiseWrapper<types.SkillActionData>;
}

export class CloudResponseRegistry {

    private registry = new Map<string, RegistryEntry>();

    /**
     * Add a cloud response entry
     * @param transID
     */
    add(transID: string): Promise<any> {
        let existing = this.registry.get(transID);
        if (existing) {
            //remove entry that had previously resolved
            this.registry.delete(transID);
            return existing.response.promise;
        } else {
            //create new entry, add it to the registry, and return the promise
            return this.createEntry(transID).response.promise;
        }
    }

    /**
     * Resolve a skill response when it arrives
     * @param transID
     * @param skillResponse
     */
    resolve(transID: string, skillResponse: types.SkillActionData) {
        let entry = this.registry.get(transID);
        const hadEntry = !!entry;
        if (!entry) {
            //got result before someone asked for it - just create an entry to hold onto
            //the result for later
            entry = this.createEntry(transID);
        }
        entry.response.resolve(skillResponse);
        //if someone had been waiting for resolution, remove it from the registry
        if (hadEntry) {
            this.registry.delete(transID);
        }
    }

    /**
     * Cull all old entries and reject outstanding promises
     * @param maxAgeMs
     */
    cull(maxAgeMs: number) {
        const now = Date.now();
        this.registry.forEach((entry, key) => {
            const age = (now - entry.timestamp);
            if (age > maxAgeMs) {
                //console.warn(`Culling entry for transID '${key}' because it is old: ${age} ms`);
                entry.response.reject(new Error(`Timeout of ${maxAgeMs} ms reached. Culling cloud response`));
                this.registry.delete(key);
            }
        });
    }

    private createEntry(id: string): RegistryEntry {
        const entry:RegistryEntry = {
            timestamp: Date.now(),
            transID: id,
            response: new ExtPromiseWrapper<types.SkillActionData>()
        };
        this.registry.set(id, entry);
        return entry;
    }
}
