import {WSClient} from 'jibo-client-framework';
import * as types from './Types';
import { Request } from './Request';
import { Events } from './Events';
import { CloudResponseRegistry } from './CloudResponseRegistry';
import { Log as JiboLog } from 'jibo-log';

const REGISTRY_CULL_TIME = 10000;

function isSuccessResult(result: types.TurnResult): result is types.SuccessTurnResult {
    return result.hasOwnProperty('result');
}

/**
 * The Client to the Jetstream on-robot service
 * @class jibo.jetstream.Client
 * @intdocs
 */
export class Client {

    /**
     * @name jibo.jetstream.Client#events
     * @type jibo.jetstream.Events
     */
    public events = new Events();
    /**
     * @name jibo.jetstream.Client#options
     * @type {jibo.jetstream.types.HostOptions}
     */
    public options: types.HostOptions;

    /**
     * @name jibo.jetstream.Client._requests
     * @type {Map}
     * @description `Map<string, Request>`
     */
    public _requests = new Map<string, Request>();

    /**
     * Logging object internal to this library
     * @private
     */
    public log: JiboLog;

    /**
     * Has the instance been initialized?
     * @private
     */
    public initialized = false;

    /**
     * Are we currently connected?
     * @private
     */
    public connected = false;

    private cloudSkillResponseRegistry = new CloudResponseRegistry();
    private cullInterval:NodeJS.Timer;
    private eventWS: WSClient;
    private vadWS: WSClient;

    /**
     * Initializes client. Connects to WS server in Jetstream
     * @returns {Promise<void>}
     * @method jibo.jetstream.Client#init
     * @param options {jibo.jetstream.types.HostOptions}
     * @param [log] {JiboLog}
     */
    async init(options: types.HostOptions, log?: JiboLog): Promise<void> {
        this.options = options;
        this.log = log || new JiboLog(`JetstreamClient`);

        const callback = () => {
            this.cloudSkillResponseRegistry.cull(REGISTRY_CULL_TIME);
        };
        //ensure that TimerSpy in Be ignores this interval and doesn't blame it on skills
        (callback as any).isGlobalTimer = true;
        this.cullInterval = setInterval(callback, REGISTRY_CULL_TIME);

        return new Promise<void>((resolve, reject) => {
            this.eventWS = new WSClient(`ws://${this.options.hostname}:${this.options.port}/events`);
            this.eventWS.once('open', () => resolve());
            this.eventWS.on('close', () => {
                this.connected = false;
                //WSClient will try to reconnect, so we are just logging that this was a problem
                //with the jetstream client specifically
                this.emitError(new Error(`Jetstream Websocket closed`));
                this.cancelAllRequests();
            });
            //on every open or reopen, emit the connected event
            this.eventWS.on('open', () => {
                this.connected = true;
                this.events.connect.emit();
            });

            // Handle event messages and pass them to the right handler
            this.eventWS.on('message', this.handleMessage);
            this.vadWS = new WSClient(`ws://${this.options.hostname}:${this.options.port}/vad`);
            this.vadWS.on('close', () => {
                //WSClient will try to reconnect, so we are just logging that this was a problem
                //with the jetstream client specifically
                this.emitError(new Error(`Jetstream VAD Websocket closed`));
            });

            // Handle event messages and pass them to the right handler
            this.vadWS.on('message', this.handleVAD);

            this.initialized = true;
        });
    }

    /**
     * Closes websocket connection
     * @method jibo.jetstream.Client#close
     */
    public close() {
        clearInterval(this.cullInterval);
        this.cullInterval = null;
        if (this.eventWS && this.eventWS.socket) {
            this.eventWS.socket.removeAllListeners('close');
            this.eventWS.socket.close();
        }
        this.eventWS = null;
        if (this.vadWS && this.vadWS.socket) {
            this.vadWS.socket.removeAllListeners('close');
            this.vadWS.socket.close();
        }
        this.vadWS = null;
    }

    /**
     * Gets the requestID from the response (if it exists).
     * @method jibo.jetstream.Client#getRequestID
     * @param  {any} response Response from the Jetstream request.
     * @return {string}
     */
    public getRequestID(response: any): string {
        if (typeof response.requestID !== 'string') {
            throw new Error(`Missing 'requestID' in response`);
        }
        return response.requestID;
    }

    /**
     * Gets a promise for a cloud skill response from a skill launch. Provided so that skill
     * launches can be handled in the SSM but cloud responses handled in Be.
     * @method jibo.jetstream.Client#getCloudSkillResponse
     * @param {string} transID
     * @return {Promise<any>}
     * @intdocs
     */
    public getCloudSkillResponse(transID: string): Promise<any> {
        return this.cloudSkillResponseRegistry.add(transID);
    }

    /**
     * Allows emitting of turn result events so that we can sort of clean up robot state in the
     * event of something going horribly wrong.
     * @private
     */
    public forceEndTurns(doGlobal = false) {
        const fakeTurnResult: types.TurnResult = {
            status: types.TurnResultType.FAILED,
            global: false,
            message: 'Jetstream disconnected'
        };
        //to allow Embodied Listen or anyone that is working off of general turn results to clean up
        //emit our failed turn result from the global events
        this.events.localTurnResult.emit(fakeTurnResult);
        if (doGlobal) {
            this.events.globalTurnResult.emit(fakeTurnResult);
        }
    }

    private handleMessage = (event: types.ServiceEvent) => {
        try {
            //WSClient handles parsing JSON for us, so no need to parse the message ourselves
            // The type of `data` in these events is a string representation of a JSON object
            if (typeof event.data === 'string') {
                event.data = JSON.parse(event.data);
            }
        } catch (error) {
            this.emitError(new Error(`Error parsing incoming event: '${error.message}'`));
            return;
        }

        if (typeof event.type !== 'string') {
            const message = JSON.stringify(event);
            this.emitError(new Error(`Incoming event missing 'type': '${message}'`));
            return;
        }

        if (!event.requestID) {
            const message = JSON.stringify(event);
            this.emitError(new Error(`Incoming event missing 'requestID': '${message}'`));
            return;
        }

        // Determines whether we attempt to pass this event down to a request object
        let shouldPassToRequest = true;

        try {
            // We emit global events for various types of events
            switch (event.type) {
                case types.ServiceEventType.ERROR:
                    this.emitError(new Error(event.data.message));
                    break;
                case types.ServiceEventType.SOS:
                    this.events.sos.emit();
                    break;
                case types.ServiceEventType.EOS:
                    this.events.eos.emit();
                    break;
                case types.ServiceEventType.SPEAKER_ID:
                    this.events.speakerID.emit(event.data);
                    break;
                case types.ServiceEventType.TURN_STARTED:
                    //in the future, global requests may not have a constant ID, so
                    //determine global/local for turn started by if we have a local request id
                    //for the turn
                    if (this._requests.has(event.requestID)) {
                        this.events.localTurnStarted.emit(event.transID);
                    } else {
                        this.events.globalTurnStarted.emit();
                    }
                    break;
                case types.ServiceEventType.TURN_RESULT:
                    // The type of `data.result` is a JSON string that needs to be further unpacked
                    if (event.data.status === types.TurnResultType.SUCCEEDED && typeof (event.data as any).result === 'string') {
                        (event.data as any).result = JSON.parse((event.data as any).result);
                    }
                    //if the turn result is a success, then standardize the result format as a ListenResult
                    const result = (event.data as any).result;
                    if (result && 'asr' in result) {
                        (event.data as any).result = new types.ListenResult(result.asr, result.nlu, result.match);
                    }

                    // Copy transaction ID into TurnResult
                    event.data.transID = event.transID;

                    //only do these things for global/local turns, not name/enrollment turns
                    //TODO: remove types.GLOBAL_REQUEST
                    if (event.data.global || event.requestID === types.GLOBAL_REQUEST) {
                        // In case we have a skill match, we emit skill match
                        const data = event.data as types.SuccessTurnResult;
                        if ((data.status === types.TurnResultType.SUCCEEDED) && data.result.match) {
                            this.emitSkillSwitch(data.result.match, data.result.asr, data.result.nlu, event.transID);
                        }
                        this.events.globalTurnResult.emit(event.data as types.ListenTurnResult);
                    } else {
                        this.emitLocalTurnResult(event.data);
                    }
                    break;
                case types.ServiceEventType.HJ_HEARD:
                    this.events.hjHeard.emit();
                    break;
                case types.ServiceEventType.HJ_ONLY:
                    this.events.hjOnly.emit();
                    break;
                case types.ServiceEventType.SKILL_ACTION:
                    // Skill actions should not be passed to request objects but be handled globally
                    shouldPassToRequest = false;
                    // Now we resolve the cloud skill response
                    this.cloudSkillResponseRegistry.resolve(event.transID, event.data);
                    break;
                case types.ServiceEventType.SKILL_REDIRECT:
                    this.emitSkillSwitch(event.data.match, event.data.asr, event.data.nlu, event.transID);
                    break;
                case types.ServiceEventType.PROACTIVE:
                    // In case we have a skill match, we emit skill switch
                    if (event.data.match) {
                        // Create empty nlu
                        const nlu = {
                            rules: [],
                            intent: '',
                            entities: {},
                        };
                        const asr = {
                            text: '',
                            confidence: 1
                        };
                        this.emitSkillSwitch(event.data.match, asr, nlu, event.transID);
                    }
                    break;
                case types.ServiceEventType.SPEAKER_ENROLLMENT:
                    //Emit speaker enrollment event
                    this.events.speakerEnrollment.emit(event.data);
                    break;
                default:
                    this.log.warn(`Unknown event type received: '${(<any>event).type}'`);
            }
        } catch (error) {
            this.emitError(error);
        }

        // Send events to specific request objects
        if (shouldPassToRequest) {
            // We look for the specific request and emit an event on it
            const request = this._requests.get(event.requestID);
            if (request) {
                // Send events to specific request objects
                if (event.type === types.ServiceEventType.ERROR) {
                    request.error.emit(new Error(`Received error: ${event.data.message}`));
                } else {
                    request.events.emit(event);
                }
            } else {
                // No request found
                if (event.requestID !== types.GLOBAL_REQUEST) {
                    //because we have 2 clients in different processes that don't know about each other, don't throw errors about this
                    //this.emitError(new Error(`No request found for id '${event.requestID}': '${message}'`));
                }
            }
        }
    }

    private handleVAD = (event: types.VADEvent) => {
        this.events.vad.emit(event);
    }

    private emitError(error: Error) {
        this.log.error(error.message);
        this.events.error.emit(error);
    }

    private emitSkillSwitch(
        match: types.GlobalMatchResponseData,
        asr: types.ASRResult,
        nlu: types.NLUResult,
        transID: string
    ) {
        this.events.skillSwitch.emit({
            skillID: match.skillID,
            onRobot: match.onRobot,
            isProactive: match.isProactive,
            skipSurprises: match.skipSurprises,
            transID: transID,
            data: new types.ListenResult(asr, nlu, match)
        });
    }

    /**
     * Emit a LocalTurnResult event (potentially infused with additional Turn data)
     * @param data Result of the LocalTurn
     * @private
     */
    private emitLocalTurnResult(data: types.TurnResult) {
        if (data.status === types.TurnResultType.SUCCEEDED && isSuccessResult(data)) {
            data.result.transID = data.transID;
            if (data.result.match) {
                data.result.cloudSkillResponse = this.getCloudSkillResponse(data.transID);
            }
        }
        this.events.localTurnResult.emit(data);
    }

    private cancelAllRequests() {
        //tell each request that it has failed, so that they and owners can do any cleanup
        const requests = this._requests.values();
        const fakeTurnResult: types.TurnResult = {
            status: types.TurnResultType.FAILED,
            global: false,
            message: 'Jetstream disconnected'
        };
        for (let request of requests) {
            request.events.emit({
                requestID: request.id,
                transID: '',
                ts: Date.now(),
                type: types.ServiceEventType.TURN_RESULT,
                data: fakeTurnResult
            });
        }
        this._requests.clear();
        this.forceEndTurns(true);
    }
}
