import { Event } from 'jibo-typed-events';
import { Log as JiboLog } from 'jibo-log';
import { Utils } from './Utils';
import { Client } from './Client';
import { ServiceEvent, ListenTurnResult, NameTurnResult, EnrollmentTurnResult, ServiceEventType, TurnResultType, ProactiveResponseData, NameSuccessTurnResult, NLUResult, LocalTurnUpdate } from './Types';

//initialized when client is initialized
let log: JiboLog;
/**
 * @private
 */
export function init(parentLog: JiboLog) {
    log = parentLog.createChild('Request');
}

/**
 * Enum of request statuses.
 * @typedef jibo.jetstream.request#RequestStatus
 * @prop ACTIVE Once a request has been sent.
 * @prop CANCELED Once a request has been canceled or unsubscribed.
 * @prop FINISHED When a request has finished (including due to error).
 */
export enum RequestStatus {
    ACTIVE = 'ACTIVE',      // Once a request has been sent
    CANCELED = 'CANCELED',  // Once a request has been canceled or unsubscribed
    FINISHED = 'FINISHED',  // When a request has finished successfully
    ERROR = 'ERROR',        // When a request has finished because of an error
}

/**
 * @description The base type of request that the client makes to the Jetstream
 * service. Keeps track of requestID, status, events and errors
 * @class jibo.jetstream.request.Request
 * @hideconstructor
 */
export class Request {

    /**
     * ID of the request.
     * @name jibo.jetstream.request.Request#id
     * @type {string}
     */
    public id: string;
    /**
     * Status of the request.
     * @name jibo.jetstream.request.Request#status
     * @type {jibo.jetstream.request#RequestStatus}
     * @default RequestStatus.ACTIVE
     */
    public status = RequestStatus.ACTIVE;
    /**
     * Events attached to the request.
     * @name jibo.jetstream.request.Request#events
     * @type {Event<jibo.jetstream.types#ServiceEvent>}
     */
    public events = new Event<ServiceEvent>(`Event`);
    /**
     * Error event attached to the request.
     * @name jibo.jetstream.request.Request#error
     * @type {Event<Error>}
     */
    public error = new Event<Error>(`Error`);

    protected resolve: Function;

    constructor(protected client: Client, id: string) {
        this.id = id;
    }
    
    /**
     * @private
     */
    protected forceEnd() {
        this.resolve({
            status: TurnResultType.CANCELED,
            global: false
        });
        this.client.forceEndTurns();
    }
}

/**
 * The request object returned by client when proactive request made
 * @export
 * @class jibo.jetstream.request.ProactiveRequest
 * @extends {jibo.jetstream.request.Request}
 * @hideconstructor
 */
export class ProactiveRequest extends Request {

    /**
     * @description This promise gets resolved when the proactive session is completed.
     * See [ProactiveResponseData](https://pegasus-api-docs.jibo.com/interfaces/proactiveresponsedata.html)
     * @name jibo.jetstream.request.ProactiveRequest#promise
     * @type {Promise<ProactiveResponseData>}
     */
    public promise: Promise<ProactiveResponseData>;

    constructor(client: Client, id: string) {
        super(client, id);
        client._requests.set(id, this);

        this.promise = new Promise<ProactiveResponseData>((resolve, reject) => {
            this.events.on(event => {
                if (event.type === ServiceEventType.PROACTIVE) {
                    process.nextTick(() => resolve(event.data as ProactiveResponseData));
                }
            });
            this.error.on(error => {
                process.nextTick(() => reject(error));
            });
        }).then((data) => {
            this.status = RequestStatus.FINISHED;
            client._requests.delete(id);
            return data;
        }).catch(error => {
            this.status = RequestStatus.ERROR;
            client._requests.delete(id);
            throw error;
        });
    }
}

/**
 * The request object returned by client when listening turn is started
 * @export
 * @class jibo.jetstream.request.LocalTurnRequest
 * @extends {jibo.jetstream.request.Request}
 * @hideconstructor
 */
export class LocalTurnRequest extends Request {

    /**
     * Promise that will yield the results of the Local Turn
     * @name jibo.jetstream.request.LocalTurnRequest#promise
     * @type {Promise<jibo.jetstream.types#ListenTurnResult>}
     */
    public promise: Promise<ListenTurnResult>;

    protected resolve: (data: ListenTurnResult) => void;

    constructor(client: Client, id: string) {
        super(client, id);
        client._requests.set(id, this);

        this.promise = new Promise<ListenTurnResult>((resolve, reject) => {
            this.resolve = resolve;

            this.events.on(event => {
                if (event.type === ServiceEventType.TURN_RESULT) {
                    //cast to the type of turn result we expect
                    const data:ListenTurnResult = event.data as ListenTurnResult;
                    process.nextTick(() => {
                        switch (data.status) {
                            case TurnResultType.SUCCEEDED:
                            case TurnResultType.FAILED:
                            case TurnResultType.INTERRUPTED:
                            case TurnResultType.CANCELED:
                            case TurnResultType.TIMEOUT:
                                resolve(data);
                                break;
                            default:
                                reject(new Error(`Unknown turn result status '${(data as any).status}'`));
                                break;
                        }
                    });
                }
            });
            this.error.on(error => {
                process.nextTick(() => reject(error));
            });
        }).then((data) => {
            if (data.status === TurnResultType.CANCELED) {
                this.status = RequestStatus.CANCELED;
            } else {
                this.status = RequestStatus.FINISHED;
            }
            client._requests.delete(id);
            return data;
        }).catch(error => {
            this.status = RequestStatus.ERROR;
            client._requests.delete(id);
            throw error;
        });
    }

    /**
     * Cancels an ongoing request
     * @returns {Promise<boolean>} `false` if the request could not be canceled.
     * @method jibo.jetstream.request.LocalTurnRequest#cancel
     */
    async cancel(): Promise<boolean> {
        if (this.status === RequestStatus.ACTIVE) {
            this.status = RequestStatus.CANCELED;
            try {
                await Utils.sendPostRequest(this.client.options, '/listen/cancel_local_turn', { requestID: this.id });
                this.resolve({
                    status: TurnResultType.CANCELED,
                    global: false
                });
                return true;
            } catch (err) {
                log.warn('Unable to cancel local turn', err);
                this.forceEnd();
            }
        }
        return false;
    }

    /**
     * Update (that is, force the completion of) an in-progress local turn with the given NLU or
     * ASR text information. This function is provided to allow a menu button push to simulate NLU
     * input to the skill. When invoked, the audio being streamed to the Hub is stopped and the Hub
     * accepts the provided ASR or NLU data as input. There is a potential race condition where the
     * given ASR/NLU data is sent to the Hub but the Hub receives the ASR or NLU result first,
     * which causes the update command to be ignored.
     * @param asrOrNlu {string|jibo.jetstream.types.NLUResult} An ASR string or NLU result to update the turn with.
     *   See [NLUResult](https://pegasus-api-docs.jibo.com/interfaces/nluresult.html)
     * @param [meta] {any} Metadata to be sent along for logging purposes.
     * @returns {Promise<void>}
     * @method jibo.jetstream.request.LocalTurnRequest#update
     */
    public async update(asrOrNlu:string|NLUResult, meta?:any): Promise<void> {
        if (this.status !== RequestStatus.ACTIVE) {
            return;
        }
        const data: LocalTurnUpdate = {
            requestID: this.id,
            clientASR: typeof asrOrNlu === 'string' ? asrOrNlu : undefined,
            clientNLU: typeof asrOrNlu === 'string' ? undefined : asrOrNlu,
            meta
        };
        try {
            await Utils.sendPostRequest(this.client.options, '/listen/update_local_turn', data);
        } catch (err) {
            log.warn('Unable to update local turn', err);
        }
    }
}

/**
 * The request object returned by client when global handler is subscribed
 * @export
 * @class jibo.jetstream.request.SubscribeGlobalRequest
 * @extends {jibo.jetstream.request.Request}
 * @hideconstructor
 */
export class SubscribeGlobalRequest extends Request {
    /**
     * Unsubscribes a global request
     * @returns {Promise<boolean>} `false` if the request could not be unsubscribed.
     * @method jibo.jetstream.request.SubscribeGlobalRequest#unsubscribe
     */
    async unsubscribe(): Promise<boolean> {
        if (this.status === RequestStatus.ACTIVE) {
            try {
                this.status = RequestStatus.CANCELED;
                await Utils.sendPostRequest(this.client.options, '/listen/unsubscribe_global', { requestID: this.id });
                return true;
            } catch (e) {
                log.warn('Unable to unsubscribe global request', e);
            }
        }
        return false;
    }
}

/**
 * The request object returned by client when enrollment turn is started
 * @export
 * @class jibo.jetstream.request.EnrollmentTurnRequest
 * @extends {jibo.jetstream.request.Request}
 * @hideconstructor
 */
export class EnrollmentTurnRequest extends Request {

    /**
     * Promise that will yield the results of the Enrollment Turn
     * @name jibo.jetstream.request.EnrollmentTurnRequest#promise
     * @type {Promise<jibo.jetstream.types#EnrollmentTurnResult>}
     */
    public promise: Promise<EnrollmentTurnResult>;

    /**
     * Ennrollment turn has started (ready for first HJ to be said)
     * @name jibo.jetstream.request.EnrollmentTurnRequest#ready
     * @type {Event<jibo.jetstream.types.EnrollmentCollectionResult>}
     */
    public ready = new Event<void>(`Enrollment Ready`);

    protected resolve: (data: EnrollmentTurnResult) => void;

    constructor(client: Client, id: string) {
        super(client, id);
        client._requests.set(id, this);

        this.promise = new Promise<EnrollmentTurnResult>((resolve, reject) => {
            this.resolve = resolve;

            this.events.on(event => {
                if (event.type === ServiceEventType.TURN_RESULT) {
                    const data:EnrollmentTurnResult = event.data as EnrollmentTurnResult;
                    process.nextTick(() => {
                        switch (data.status) {
                            case TurnResultType.SUCCEEDED:
                            case TurnResultType.FAILED:
                            case TurnResultType.INTERRUPTED:
                            case TurnResultType.CANCELED:
                            case TurnResultType.TIMEOUT:
                                resolve(data);
                                break;
                            default:
                                reject(`Unknown turn result status '${(data as any).status}'`);
                                break;
                        }
                    });
                } else if (event.type === ServiceEventType.TURN_STARTED) {
                    this.ready.emit();
                }
            });
            this.error.on(error => {
                process.nextTick(() => reject(error));
            });
        }).then((data) => {
            if (data.status === TurnResultType.CANCELED) {
                this.status = RequestStatus.CANCELED;
            } else {
                this.status = RequestStatus.FINISHED;
            }
            client._requests.delete(id);
            //cast as any because SpeakerModelResult is very simple, but TurnResults are not
            return data;
        }).catch(error => {
            this.status = RequestStatus.ERROR;
            client._requests.delete(id);
            throw error;
        });
    }

    /**
     * Cancels an ongoing request
     * @returns {Promise<boolean>} `false` if the request could not be canceled.
     * @method jibo.jetstream.request.EnrollmentTurnRequest#cancel
     */
    async cancel(): Promise<boolean> {
        if (this.status === RequestStatus.ACTIVE) {
            this.status = RequestStatus.CANCELED;
            try {
                await Utils.sendPostRequest(this.client.options, '/listen/cancel_local_turn', { requestID: this.id });
                this.resolve({
                    status: TurnResultType.CANCELED,
                    global: false
                });
                return true;
            } catch (err) {
                //eat error for now
                log.warn('Unable to cancel voice enrollment turn', err);
                this.forceEnd();
            }
        }
        return false;
    }
}

