/**
 * @name jibo.jetstream#client
 * @type jibo.jetstream.Client
 * @intdocs
 */
let client = new Client();

/**
 * Global events from the jetstream client.
 * @name jibo.jetstream#events
 * @type jibo.jetstream.Events
 * @intdocs
 */
export let events: Events = client.events;

/**
 * Initializes client. Connects to WS server in Jetstream
 * @method jibo.jetstream#init
 * @param options {jibo.jetstream.types.HostOptions}
 * @param [log] {JiboLog}
 * @returns {Promise<void>}
 */
export async function init(options: types.HostOptions, log?: JiboLog): Promise<void> {
    if (client.initialized) {
        console.warn("Client has already been initialized. No action taken.");
        return;
    }
    await client.init(options, log);
    initHW(client.log);
    request.init(client.log);
}

/**
 * Closes client. Disconnects to WS server in Jetstream
 * @method jibo.jetstream#close
 */
export function close(): void {
    client.close();
}

/**
 * Notifies the Proactive Selector of an opportunity for proactive behavior
 * @method jibo.jetstream#triggerProactive
 * @param {ProactiveRequestData} data See [ProactiveRequestData](https://pegasus-api-docs.jibo.com/index.html#proactiverequestdata)
 * @returns {Promise<jibo.jetstream.request.ProactiveRequest>}
 */
export async function triggerProactive(data: types.ProactiveRequestData): Promise<request.ProactiveRequest> {
    if (!client.connected) {
        client.log.warn('Disconnected, waiting for reconnect before triggerProactive');
        await events.connect.waitFor(5000);
    }
    const ret = await Utils.sendPostRequest(client.options, '/proactive/trigger', data);
    return new request.ProactiveRequest(client, client.getRequestID(ret));
}

