/**
 * Changes how hotword listening is handled, from fully disabled to adding additional API.AI grammars.
 * @method jibo.jetstream#setHotwordMode
 * @param {jibo.jetstream.types.HotwordListenMode} mode Mode to set to.
 * @param {string[]} [rules] Additional grammars
 * @returns {jibo.jetstream.HotwordModeToken}
 */
export function setHotwordMode(mode:types.HotwordListenMode.Disabled): HotwordModeToken;
export function setHotwordMode(mode:types.HotwordListenMode.HJ_Only): HotwordModeToken;
export function setHotwordMode(mode:types.HotwordListenMode.ASR_Only): HotwordModeToken;
export function setHotwordMode(mode:types.HotwordListenMode.Custom_NLU_Only, rules:string[]): HotwordModeToken;
export function setHotwordMode(mode:types.HotwordListenMode.Custom_NLU_Added, rules:string[]): HotwordModeToken;
export function setHotwordMode(mode:types.HotwordListenMode, rules?:string[]): HotwordModeToken {
    return generateToken(mode, rules);
}

/**
 * Resets the hotword mode, releasing all tokens.
 * @method jibo.jetstream#resetHotwordMode
 * @return {Promise<void>}
 */
export function resetHotwordMode(): Promise<void> {
    return resetMode();
}

