/**
 * Create a model from all the speaker’s utterances collected so far.
 * @method jibo.jetstream#createSpeakerModel
 * @param {string} speakerID UUID of the speaker whose model is being created
 * @param {boolean} [append] Use true if you want the samples to be added to the existing speaker model. Use false if you want to replace the existing speaker model.
 * @returns {Promise<jibo.jetstream.types.SpeakerModelResult>}
 * @intdocs
 */
export async function createSpeakerModel(speakerID: string, append = false): Promise<types.SpeakerModelResult> {
    if (!client.connected) {
        client.log.warn('Disconnected, waiting for reconnect before createSpeakerModel');
        await events.connect.waitFor(5000);
    }
    const result:types.SpeakerModelResult = await Utils.sendPostRequest(client.options, '/enroll/create_speaker_model', {speakerID, append});
    //handle {message:"FAILURE"} and "FAILURE" as possible responses, just in case (we expect the first)
    if (result.message) {
        return Promise.reject(result.message);
    }
    if (typeof result === 'string') {
        return Promise.reject(result);
    }
    return result;
}

/**
 * Removes sample Hey Jibo utterances that have not been used to create a speaker model.
 * @method jibo.jetstream#removePendingSamples
 * @param {string} speakerID UUID of the speaker whose unused samples should be cleared
 * @returns {Promise<void>}
 * @intdocs
 */
export async function removePendingSamples(speakerID: string): Promise<void> {
    if (!client.connected) {
        client.log.warn('Disconnected, waiting for reconnect before removePendingSamples');
        await events.connect.waitFor(5000);
    }
    const result = await Utils.sendPostRequest(client.options, '/enroll/remove_pending_samples', {speakerID});
    //handle {message:"FAILURE"} and "FAILURE" as possible responses, just in case (we expect the first)
    if (result.message) {
        return Promise.reject(result.message);
    }
    if (typeof result === 'string') {
        return Promise.reject(result);
    }
    return result;
}

/**
 * Gets list of speakers enrolled in the system
 * @method jibo.jetstream#getEnrolledSpeakers
 * @returns {Promise<string[]>} List of speakers enrolled in the system
 * @intdocs
 */
export async function getEnrolledSpeakers(): Promise<string[]> {
    if (!client.connected) {
        client.log.warn('Disconnected, waiting for reconnect before getEnrolledSpeakers');
        await events.connect.waitFor(5000);
    }
    const result = await Utils.sendPostRequest(client.options, '/enroll/get_enrolled_speakers', {});
    if (!result.speakers) {
        client.log.warn(`Response from get_enrolled_speakers did not contain speakers - `, result);
        return [];
    }
    return result.speakers;
}

/**
 * Needed to make a fresh client in tests.
 */
export function _resetInstance() {
    client = new Client();
    events = client.events;
}
