import * as http from 'http';
import { HostOptions } from './Types';

const MAX_RETRIES = 5;

/**
 * Class containing Jetstream Client Utilities.
 * @class jibo.jetstream.Utils
 * @intdocs
 */
export class Utils {

    /**
     * @description Helper method to send post requests to a provided location.
     * @method jibo.jetstream.Utils#sendPostRequest
     * @param hostOptions {jibo.jetstream.types.HostOptions} Hostname and port information.
     * @param path {string} Path/URL to make the request to.
     * @param postData {any} Data to be posted on the request.
     * @return {Promise<any>} Promise containing the result of the request.
     */
    static async sendPostRequest(hostOptions: HostOptions, path: string, postData: any, retries = 0): Promise<any> {
        // Build the post string from an object
        const postDataString = JSON.stringify(postData);

        // An object of options to indicate where to post to
        const postOptions = {
            host: hostOptions.hostname,
            port: hostOptions.port,
            path: path,
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'Content-Length': Buffer.byteLength(postDataString)
            }
        };

        return new Promise((resolve, reject) => {
            // Set up the request
            const postReq = http.request(postOptions, (response) => {
                response.setEncoding('utf8');
                let responseData = '';
                response.on('data', (chunk) => {
                    responseData += chunk;
                });
                response.on('end', () => {
                    //Rick is trying to solve an odd bug in Jetstream, so in the meantime
                    //is sending a 417 error if the bug happens so we know to retry our
                    //last request
                    if (response.statusCode === 417) {
                        if (retries >= MAX_RETRIES) {
                            return reject(new Error('Attempted too many retries - ' + responseData));
                        }
                        return resolve(Utils.sendPostRequest(hostOptions, path, postData, retries + 1));
                    }
                    try {
                        //Jetstream seems to be sending an empty string for empty non-error
                        //responses. in order to not have problems, we are just handling that
                        //safely here
                        if (responseData === '') {
                            return resolve({});
                        }
                        const data = JSON.parse(responseData);
                        resolve(data);
                    } catch (error) {
                        reject(new Error(`Error parsing response: '${error.message}' - Response: ${responseData} - Path used: ${path} - Original POST: ${postDataString}`));
                    }
                });
                response.on('error', reject);
            });

            // post the data
            postReq.write(postDataString);
            postReq.end();
        });
    }
}
